1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
14	
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const LOYALTY_YEARS_THRESHOLD = 2;
20	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
21	
22	type Scenario = {
23	  customer: { yearsWithMHPCO: number };
24	  steps: Array<{ op: "quote"; items: Item[] }>;
25	};
26	
27	type QuoteResult = { premium: number };
28	
29	const COMPONENT_BLOCK_SIZE = 3;
30	const COMPONENT_BLOCK_PREMIUM = 60;
31	
32	const isComponentBlock = (group: Item[]): boolean => group.length === COMPONENT_BLOCK_SIZE;
33	
34	const sumOfBasePremiums = (items: Item[]): number =>
35	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
36	
37	const groupByType = (items: Item[]): Item[][] =>
38	  Object.values(Object.groupBy(items, (item) => item.type));
39	
40	const basePremiumForGroup = (group: Item[]): number =>
41	  isComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);
42	
43	const basePremiumFor = (items: Item[]): number =>
44	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
45	
46	type SurchargeRule = { rate: number; applies: (item: Item) => boolean };
47	
48	const SURCHARGE_RULES: SurchargeRule[] = [
49	  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
50	  {
51	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
52	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
53	  },
54	];
55	
56	const surchargeForRule = (items: Item[], rule: SurchargeRule): number =>
57	  items.reduce(
58	    (sum, item) => (rule.applies(item) ? sum + BASE_PREMIUMS[item.type] * rule.rate : sum),
59	    0,
60	  );
61	
62	const surchargesFor = (items: Item[]): number =>
63	  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);
64	
65	type Customer = { yearsWithMHPCO: number };
66	type PolicyContext = { customer: Customer; isFollowUp: boolean };
67	
68	type PolicyDiscountRule = { rate: number; applies: (context: PolicyContext) => boolean };
69	
70	const POLICY_DISCOUNT_RULES: PolicyDiscountRule[] = [
71	  {
72	    rate: LOYALTY_DISCOUNT_RATE,
73	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
74	  },
75	  {
76	    rate: FOLLOW_UP_DISCOUNT_RATE,
77	    applies: ({ isFollowUp }) => isFollowUp,
78	  },
79	];
80	
81	const policyDiscountsFor = (base: number, context: PolicyContext): number =>
82	  POLICY_DISCOUNT_RULES.reduce(
83	    (total, rule) => (rule.applies(context) ? total + base * rule.rate : total),
84	    0,
85	  );
86	
87	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
88	  const base = basePremiumFor(items);
89	  const surcharges = surchargesFor(items);
90	  const discounts = policyDiscountsFor(base, { customer, isFollowUp });
91	  return {
92	    premium: Math.ceil(base + surcharges - discounts + base * FIRST_INSURANCE_RATE + PROCESSING_FEE),
93	  };
94	};
95	
96	export const processScenario = ({ customer, steps }: Scenario): { results: QuoteResult[] } => ({
97	  results: steps.map((step, index) => quotePremium(step.items, customer, index > 0)),
98	});
